const MAX_PENDING_CLIENT_REQUESTS_PER_CONNECTION: usize = 64;
#[derive(Clone, Copy, Debug)]
pub struct GatewayV2Timeouts {
    pub initialize: Duration,
    pub client_send: Duration,
    pub reconnect_retry_backoff: Duration,
    pub max_pending_server_requests: usize,
    pub max_pending_client_requests: usize,
}

impl Default for GatewayV2Timeouts {
    fn default() -> Self {
        Self {
            initialize: Duration::from_secs(30),
            client_send: Duration::from_secs(10),
            reconnect_retry_backoff: Duration::from_secs(1),
            max_pending_server_requests: MAX_PENDING_SERVER_REQUESTS_PER_CONNECTION,
            max_pending_client_requests: MAX_PENDING_CLIENT_REQUESTS_PER_CONNECTION,
        }
    }
}

#[derive(Clone)]
pub struct GatewayV2State {
    pub auth: GatewayAuth,
    pub admission: GatewayAdmissionController,
    pub observability: GatewayObservability,
    pub scope_registry: Arc<GatewayScopeRegistry>,
    pub session_factory: Option<Arc<GatewayV2SessionFactory>>,
    pub timeouts: GatewayV2Timeouts,
}

impl GatewayV2DownstreamRouter {
    #[cfg(test)]
    async fn connect(
        session_factory: &GatewayV2SessionFactory,
        initialize_params: &InitializeParams,
        request_context: &GatewayRequestContext,
    ) -> io::Result<Self> {
        Self::connect_with_timeouts(
            session_factory,
            initialize_params,
            request_context,
            &GatewayV2Timeouts::default(),
        )
        .await
    }

    async fn connect_with_timeouts(
        session_factory: &GatewayV2SessionFactory,
        initialize_params: &InitializeParams,
        request_context: &GatewayRequestContext,
        timeouts: &GatewayV2Timeouts,
    ) -> io::Result<Self> {
        info!("gateway downstream router connect starting");
        let sessions = session_factory
            .connect(initialize_params, request_context)
            .await?;
        info!(
            session_count = sessions.len(),
            "gateway downstream router connect finished"
        );
        let (event_tx, event_rx) = mpsc::channel(sessions.len().max(1) * 4);
        let reconnect_state = match session_factory {
            GatewayV2SessionFactory::RemoteSingle { connect_args, .. } => {
                Some(GatewayV2ReconnectState {
                    configured_worker_ids: vec![0],
                    worker_websocket_urls: vec![connect_args.websocket_url().to_string()],
                    session_factory: session_factory.clone(),
                    initialize_params: initialize_params.clone(),
                    request_context: request_context.clone(),
                    retry_backoff: timeouts.reconnect_retry_backoff,
                })
            }
            GatewayV2SessionFactory::RemoteMulti { connect_args, .. } => {
                Some(GatewayV2ReconnectState {
                    configured_worker_ids: (0..connect_args.len()).collect(),
                    worker_websocket_urls: connect_args
                        .iter()
                        .map(|args| args.websocket_url().to_string())
                        .collect(),
                    session_factory: session_factory.clone(),
                    initialize_params: initialize_params.clone(),
                    request_context: request_context.clone(),
                    retry_backoff: timeouts.reconnect_retry_backoff,
                })
            }
            _ => None,
        };
        let mut router = Self {
            workers: Vec::with_capacity(sessions.len()),
            event_tx,
            event_rx,
            shutdown_txs: Vec::with_capacity(sessions.len()),
            event_tasks: Vec::with_capacity(sessions.len()),
            next_worker: 0,
            initialized_notification_sent: false,
            active_fs_watches: HashMap::new(),
            reconnect_retry_after: HashMap::new(),
            reconnect_state,
        };

        for session in sessions {
            router.add_session(session);
        }

        Ok(router)
    }

    fn single_worker(&self) -> bool {
        self.workers.len() == 1
    }

    fn latest_worker_with_id(&self, worker_id: Option<usize>) -> Option<&DownstreamWorkerHandle> {
        self.workers
            .iter()
            .rev()
            .find(|worker| worker.worker_id == worker_id)
    }

    pub(crate) fn multi_worker_topology(&self) -> bool {
        self.reconnect_state
            .as_ref()
            .is_some_and(|state| state.configured_worker_ids.len() > 1)
            || self.workers.len() > 1
    }

    fn primary_worker(&self) -> io::Result<&DownstreamWorkerHandle> {
        if self.multi_worker_topology() {
            return self.latest_worker_with_id(Some(0)).ok_or_else(|| {
                io::Error::other("gateway v2 connection has no downstream app-server sessions")
            });
        }

        self.workers.first().ok_or_else(|| {
            io::Error::other("gateway v2 connection has no downstream app-server sessions")
        })
    }

    fn worker_count(&self) -> usize {
        self.workers.len()
    }

    fn has_worker(&self, worker_id: Option<usize>) -> bool {
        self.workers
            .iter()
            .any(|worker| worker.worker_id == worker_id)
    }

    fn next_thread_start_worker(&mut self) -> io::Result<&DownstreamWorkerHandle> {
        let Some(index) = self.next_worker_index_with_health_and_account_capacity() else {
            return Err(io::Error::other(
                "gateway v2 connection has no healthy downstream app-server sessions with available account capacity",
            ));
        };
        Ok(&self.workers[index])
    }

    fn next_worker_index_with_health_and_account_capacity(&mut self) -> Option<usize> {
        if self.workers.is_empty() {
            return None;
        }

        let start = self.next_worker;
        self.next_worker = self.next_worker.wrapping_add(1);
        (0..self.workers.len())
            .map(|offset| (start + offset) % self.workers.len())
            .find(|index| {
                self.workers[*index].worker_id.is_none_or(|worker_id| {
                    self.worker_is_healthy(worker_id) && self.worker_account_has_capacity(worker_id)
                })
            })
    }

    fn next_thread_start_worker_for_project(
        &mut self,
        scope_registry: &GatewayScopeRegistry,
        context: &GatewayRequestContext,
    ) -> io::Result<&DownstreamWorkerHandle> {
        if let Some(worker_id) = scope_registry.select_project_worker_id_with_accounts(
            context,
            self.workers
                .iter()
                .filter_map(|worker| worker.worker_id)
                .filter(|worker_id| {
                    self.worker_is_healthy(*worker_id)
                        && self.worker_account_has_capacity(*worker_id)
                }),
            |worker_id| self.worker_account_id(worker_id),
        ) && let Some(index) = self
            .workers
            .iter()
            .rposition(|worker| worker.worker_id == Some(worker_id))
        {
            return Ok(&self.workers[index]);
        }
        self.next_thread_start_worker()
    }

    fn worker_for_thread(
        &self,
        scope_registry: &GatewayScopeRegistry,
        thread_id: &str,
    ) -> io::Result<&DownstreamWorkerHandle> {
        let worker_id = scope_registry.thread_worker_id(thread_id);
        self.latest_worker_with_id(worker_id)
            .or_else(|| self.latest_worker_with_id(None))
            .ok_or_else(|| {
                io::Error::new(
                    ErrorKind::NotFound,
                    format!("gateway has no downstream worker route for thread {thread_id}"),
                )
            })
    }

    async fn next_event(&mut self) -> Option<DownstreamWorkerEvent> {
        self.event_rx.recv().await
    }

    async fn shutdown(self) -> io::Result<()> {
        for shutdown_tx in self.shutdown_txs {
            let _ = shutdown_tx.send(());
        }
        for event_task in self.event_tasks {
            event_task.await.map_err(|err| {
                io::Error::other(format!("gateway v2 event task failed: {err}"))
            })??;
        }
        Ok(())
    }

    fn remove_worker(&mut self, worker_id: Option<usize>) -> bool {
        let Some(index) = self
            .workers
            .iter()
            .position(|worker| worker.worker_id == worker_id)
        else {
            return false;
        };
        self.workers.remove(index);
        if index < self.shutdown_txs.len() {
            self.shutdown_txs.remove(index);
        }
        if index < self.event_tasks.len() {
            self.event_tasks.remove(index);
        }
        if self.next_worker >= self.workers.len() && !self.workers.is_empty() {
            self.next_worker %= self.workers.len();
        }
        true
    }

    async fn reconnect_missing_workers(&mut self, observability: &GatewayObservability) {
        self.reconnect_missing_workers_at(Instant::now(), observability, true)
            .await;
    }

    async fn reconnect_missing_workers_for_request(
        &mut self,
        observability: &GatewayObservability,
    ) {
        if let Some(delay) = self.shortest_request_reconnect_backoff(Instant::now()) {
            tokio::time::sleep(delay).await;
        }
        self.reconnect_missing_workers_at(Instant::now(), observability, true)
            .await;
    }

    async fn reconnect_missing_workers_after_disconnect(
        &mut self,
        observability: &GatewayObservability,
    ) {
        self.reconnect_missing_workers_at(Instant::now(), observability, false)
            .await;
    }

    async fn reconnect_missing_workers_at(
        &mut self,
        now: Instant,
        observability: &GatewayObservability,
        respect_backoff: bool,
    ) {
        let Some(reconnect_state) = self.reconnect_state.clone() else {
            return;
        };
        if self.workers.len() >= reconnect_state.configured_worker_ids.len() {
            return;
        }

        for worker_id in reconnect_state.configured_worker_ids {
            if self.has_worker(Some(worker_id)) {
                continue;
            }
            let websocket_url = reconnect_state
                .worker_websocket_urls
                .get(worker_id)
                .map_or("<unknown>", String::as_str);
            if respect_backoff && !self.should_attempt_worker_reconnect(worker_id, now) {
                observability.record_v2_worker_reconnect(worker_id, "backoff_suppressed");
                let reconnect_backoff_remaining_seconds = self
                    .reconnect_retry_after
                    .get(&worker_id)
                    .filter(|retry_after| **retry_after > now)
                    .map(|retry_after| retry_after.duration_since(now).as_secs());
                warn!(
                    worker_id,
                    websocket_url,
                    initialized_notification_sent = self.initialized_notification_sent,
                    active_fs_watch_count = self.active_fs_watches.len(),
                    retry_backoff_seconds = reconnect_state.retry_backoff.as_secs(),
                    reconnect_backoff_remaining_seconds,
                    "suppressing missing downstream worker reconnect while retry backoff is active"
                );
                continue;
            }
            let mut last_error = None;
            for attempt_index in 0..3 {
                observability.record_v2_worker_reconnect(worker_id, "attempt");
                info!(
                    worker_id,
                    websocket_url,
                    attempt_index,
                    initialized_notification_sent = self.initialized_notification_sent,
                    active_fs_watch_count = self.active_fs_watches.len(),
                    retry_backoff_seconds = reconnect_state.retry_backoff.as_secs(),
                    "attempting to reconnect missing downstream worker session"
                );
                match reconnect_state
                    .session_factory
                    .connect_worker_once(
                        worker_id,
                        &reconnect_state.initialize_params,
                        &reconnect_state.request_context,
                    )
                    .await
                {
                    Ok(session) => {
                        if let Err(err) = self.replay_connection_state(&session).await {
                            let err_message = err.to_string();
                            last_error = Some(err);
                            observability.record_v2_worker_reconnect(worker_id, "replay_failure");
                            warn!(
                                worker_id,
                                websocket_url,
                                attempt_index,
                                initialized_notification_sent = self.initialized_notification_sent,
                                active_fs_watch_count = self.active_fs_watches.len(),
                                retry_backoff_seconds = reconnect_state.retry_backoff.as_secs(),
                                err = %err_message,
                                "failed to replay connection state to reconnected downstream worker session"
                            );
                            continue;
                        }
                        self.clear_worker_reconnect_failure(worker_id);
                        reconnect_state
                            .session_factory
                            .mark_worker_healthy(worker_id);
                        observability.record_v2_worker_reconnect(worker_id, "success");
                        info!(
                            worker_id,
                            websocket_url,
                            attempt_index,
                            initialized_notification_sent = self.initialized_notification_sent,
                            active_fs_watch_count = self.active_fs_watches.len(),
                            "reconnected missing downstream worker session"
                        );
                        self.add_session(session);
                        last_error = None;
                        break;
                    }
                    Err(err) => {
                        let detail = err.to_string();
                        if let Some(reason) = downstream_protocol_violation_reason(&detail) {
                            log_downstream_reconnect_protocol_violation(
                                &reconnect_state.request_context,
                                worker_id,
                                websocket_url,
                                reason,
                                &detail,
                            );
                            observability.record_v2_worker_protocol_violation(
                                Some(worker_id),
                                "downstream",
                                reason,
                            );
                        }
                        observability.record_v2_worker_reconnect(worker_id, "connect_failure");
                        warn!(
                            worker_id,
                            websocket_url,
                            attempt_index,
                            initialized_notification_sent = self.initialized_notification_sent,
                            active_fs_watch_count = self.active_fs_watches.len(),
                            retry_backoff_seconds = reconnect_state.retry_backoff.as_secs(),
                            err = %detail,
                            "failed to reconnect missing downstream worker session"
                        );
                        last_error = Some(err);
                    }
                }
            }
            if last_error.is_some() && !self.has_worker(Some(worker_id)) {
                self.record_worker_reconnect_failure(worker_id, now, reconnect_state.retry_backoff);
            }
        }
    }

    fn add_session(&mut self, session: GatewayV2ConnectedSession) {
        let (worker, shutdown_tx, event_task) =
            spawn_downstream_worker_session(self.event_tx.clone(), session);
        if self.workers.len() != self.shutdown_txs.len()
            || self.workers.len() != self.event_tasks.len()
        {
            self.workers.push(worker);
            self.shutdown_txs.push(shutdown_tx);
            self.event_tasks.push(event_task);
            return;
        }
        let mut sessions = self
            .workers
            .drain(..)
            .zip(self.shutdown_txs.drain(..))
            .zip(self.event_tasks.drain(..))
            .map(|((worker, shutdown_tx), event_task)| (worker, shutdown_tx, event_task))
            .collect::<Vec<_>>();
        sessions.push((worker, shutdown_tx, event_task));
        sessions.sort_by_key(|(worker, _, _)| worker.worker_id.unwrap_or(usize::MAX));
        for (worker, shutdown_tx, event_task) in sessions {
            self.workers.push(worker);
            self.shutdown_txs.push(shutdown_tx);
            self.event_tasks.push(event_task);
        }
    }

    fn mark_initialized(&mut self) {
        self.initialized_notification_sent = true;
    }

    fn record_fs_watch(&mut self, params: FsWatchParams) {
        self.active_fs_watches
            .insert(params.watch_id.clone(), params);
    }

    fn clear_fs_watch(&mut self, watch_id: &str) {
        self.active_fs_watches.remove(watch_id);
    }

    fn should_attempt_worker_reconnect(&self, worker_id: usize, now: Instant) -> bool {
        self.reconnect_retry_after
            .get(&worker_id)
            .is_none_or(|retry_after| *retry_after <= now)
    }

    fn shortest_request_reconnect_backoff(&self, now: Instant) -> Option<Duration> {
        let reconnect_state = self.reconnect_state.as_ref()?;
        self.reconnect_retry_after
            .iter()
            .filter(|(worker_id, retry_after)| {
                reconnect_state.configured_worker_ids.contains(worker_id) && **retry_after > now
            })
            .filter_map(|(_, retry_after)| {
                let delay = retry_after.duration_since(now);
                (delay <= reconnect_state.retry_backoff).then_some(delay)
            })
            .min()
    }

    fn record_worker_reconnect_failure(
        &mut self,
        worker_id: usize,
        now: Instant,
        retry_backoff: Duration,
    ) {
        self.reconnect_retry_after
            .insert(worker_id, now + retry_backoff);
    }

    fn clear_worker_reconnect_failure(&mut self, worker_id: usize) {
        self.reconnect_retry_after.remove(&worker_id);
    }

    fn ensure_all_configured_workers_present_for(&self, label: &str) -> io::Result<()> {
        let Some(reconnect_state) = &self.reconnect_state else {
            return Ok(());
        };

        let missing_worker_ids = reconnect_state
            .configured_worker_ids
            .iter()
            .copied()
            .filter(|worker_id| !self.has_worker(Some(*worker_id)))
            .collect::<Vec<_>>();
        if missing_worker_ids.is_empty() {
            return Ok(());
        }

        Err(io::Error::other(FailClosedMultiWorkerRouteError {
            message: format!(
                "required worker routes are unavailable for {label}: {missing_worker_ids:?}"
            ),
        }))
    }

    fn ensure_primary_worker_present_for(&self, label: &str) -> io::Result<()> {
        if self.has_worker(Some(0)) {
            return Ok(());
        }

        Err(io::Error::other(FailClosedMultiWorkerRouteError {
            message: format!("primary worker route is unavailable for {label}"),
        }))
    }

    pub(crate) fn unavailable_worker_route_diagnostics(
        &self,
        now: Instant,
    ) -> Vec<UnavailableWorkerRouteDiagnostics> {
        let Some(reconnect_state) = &self.reconnect_state else {
            return Vec::new();
        };

        reconnect_state
            .configured_worker_ids
            .iter()
            .copied()
            .filter(|worker_id| !self.has_worker(Some(*worker_id)))
            .map(|worker_id| {
                let reconnect_backoff_remaining_seconds = self
                    .reconnect_retry_after
                    .get(&worker_id)
                    .filter(|retry_after| **retry_after > now)
                    .map(|retry_after| retry_after.duration_since(now).as_secs());
                UnavailableWorkerRouteDiagnostics {
                    worker_id,
                    websocket_url: reconnect_state
                        .worker_websocket_urls
                        .get(worker_id)
                        .cloned()
                        .unwrap_or_else(|| "<unknown>".to_string()),
                    reconnect_backoff_active: reconnect_backoff_remaining_seconds.is_some(),
                    reconnect_backoff_remaining_seconds,
                }
            })
            .collect()
    }

    fn websocket_url_for_worker_id(&self, worker_id: Option<usize>) -> &str {
        if let Some(worker_websocket_url) = self
            .workers
            .iter()
            .rev()
            .find(|worker| worker.worker_id == worker_id)
            .and_then(|worker| worker.worker_websocket_url.as_deref())
        {
            return worker_websocket_url;
        }

        worker_id
            .and_then(|worker_id| {
                self.reconnect_state
                    .as_ref()
                    .and_then(|state| state.worker_websocket_urls.get(worker_id))
            })
            .map_or("<unknown>", String::as_str)
    }

    fn worker_account_id(&self, worker_id: usize) -> Option<String> {
        self.reconnect_state
            .as_ref()
            .and_then(|state| state.session_factory.worker_account_id(worker_id))
    }

    fn worker_account_has_capacity(&self, worker_id: usize) -> bool {
        self.reconnect_state
            .as_ref()
            .is_none_or(|state| state.session_factory.worker_account_has_capacity(worker_id))
    }

    fn worker_is_healthy(&self, worker_id: usize) -> bool {
        self.reconnect_state
            .as_ref()
            .is_none_or(|state| state.session_factory.worker_is_healthy(worker_id))
    }

    pub(crate) fn mark_worker_account_exhausted(&self, worker_id: usize, reason: String) -> bool {
        if let Some(state) = &self.reconnect_state {
            return state
                .session_factory
                .mark_worker_account_exhausted(worker_id, reason);
        }
        false
    }

    pub(crate) fn mark_worker_account_available(&self, worker_id: usize) -> bool {
        if let Some(state) = &self.reconnect_state {
            return state
                .session_factory
                .mark_worker_account_available(worker_id);
        }
        false
    }

    async fn replay_connection_state(&self, session: &GatewayV2ConnectedSession) -> io::Result<()> {
        let request_handle = session.app_server.request_handle();
        if self.initialized_notification_sent {
            request_handle
                .notify(ClientNotification::Initialized)
                .await?;
        }
        for params in self.active_fs_watches.values() {
            request_handle
                .request_typed::<FsWatchResponse>(ClientRequest::FsWatch {
                    request_id: RequestId::String(format!(
                        "gateway-replay-fs-watch:{watch_id}",
                        watch_id = params.watch_id
                    )),
                    params: params.clone(),
                })
                .await
                .map_err(io::Error::other)?;
        }
        Ok(())
    }
}

fn spawn_downstream_worker_session(
    event_tx: mpsc::Sender<DownstreamWorkerEvent>,
    session: GatewayV2ConnectedSession,
) -> (
    DownstreamWorkerHandle,
    tokio::sync::oneshot::Sender<()>,
    JoinHandle<io::Result<()>>,
) {
    let worker_id = session.worker_id;
    let worker_websocket_url = session.worker_websocket_url;
    let request_handle = session.app_server.request_handle();
    let (shutdown_tx, mut shutdown_rx) = tokio::sync::oneshot::channel();
    let mut app_server = session.app_server;
    let event_task = tokio::spawn(async move {
        loop {
            tokio::select! {
                _ = &mut shutdown_rx => {
                    break;
                }
                event = app_server.next_event() => {
                    let end_of_stream = event.is_none();
                    let terminal_disconnect = matches!(
                        event,
                        Some(AppServerEvent::Disconnected { .. })
                    );
                    if event_tx
                        .send(DownstreamWorkerEvent { worker_id, event })
                        .await
                        .is_err()
                    {
                        break;
                    }
                    if end_of_stream || terminal_disconnect {
                        break;
                    }
                }
            }
        }

        app_server.shutdown().await
    });
    (
        DownstreamWorkerHandle {
            worker_id,
            worker_websocket_url,
            request_handle,
        },
        shutdown_tx,
        event_task,
    )
}

pub async fn websocket_upgrade_handler(
    websocket: WebSocketUpgrade,
    State(state): State<GatewayV2State>,
    headers: HeaderMap,
) -> impl IntoResponse {
    if headers.contains_key(ORIGIN) {
        return (
            StatusCode::FORBIDDEN,
            "gateway websocket connections must not include an Origin header",
        )
            .into_response();
    }

    if !is_authorized(&state.auth, &headers) {
        return GatewayAuthError.into_response();
    }

    let context = match GatewayRequestContext::from_headers(&headers) {
        Ok(context) => context,
        Err(err) => return err.into_response(),
    };

    let Some(session_factory) = state.session_factory else {
        return (
            StatusCode::NOT_IMPLEMENTED,
            "gateway app-server v2 compatibility is not enabled for this runtime",
        )
            .into_response();
    };

    websocket
        .on_upgrade(move |socket| async move {
            if let Err(err) = run_websocket_connection(
                socket,
                session_factory,
                state.admission,
                state.observability,
                state.scope_registry,
                context,
                state.timeouts,
            )
            .await
            {
                warn!(%err, "gateway v2 websocket connection failed");
            }
        })
        .into_response()
}

fn is_authorized(auth: &GatewayAuth, headers: &HeaderMap) -> bool {
    match auth {
        GatewayAuth::Disabled => true,
        GatewayAuth::BearerToken { token } => headers
            .get(AUTHORIZATION)
            .and_then(|value| value.to_str().ok())
            .is_some_and(|value| value == format!("Bearer {token}")),
    }
}

async fn run_websocket_connection(
    mut socket: WebSocket,
    session_factory: Arc<GatewayV2SessionFactory>,
    admission: GatewayAdmissionController,
    observability: GatewayObservability,
    scope_registry: Arc<GatewayScopeRegistry>,
    context: GatewayRequestContext,
    timeouts: GatewayV2Timeouts,
) -> io::Result<()> {
    let connection_started_at = Instant::now();
    let initialize_started_at = Instant::now();
    let connection_id = observability
        .v2_connection_health()
        .mark_connection_started();
    let run_result = match async {
        let initialize_request =
            match recv_initialize_request(&mut socket, timeouts, &observability, &context).await {
            Ok(request) => request,
            Err(err) if err.kind() == ErrorKind::TimedOut => {
                send_observed_close_frame(
                    &mut socket,
                    &observability,
                    &context,
                    close_code::POLICY,
                    INITIALIZE_TIMEOUT_CLOSE_REASON,
                    timeouts.client_send,
                )
                .await?;
                observe_v2_request(
                    &observability,
                    &context,
                    "initialize",
                    "timed_out",
                    initialize_started_at.elapsed(),
                );
                return Ok(GatewayV2ConnectionRunResult {
                    outcome: "initialize_timed_out",
                    detail: Some(INITIALIZE_TIMEOUT_CLOSE_REASON.to_string()),
                    pending_client_request_count: 0,
                    pending_client_request_worker_counts: Vec::new(),
                    pending_client_request_method_counts: Vec::new(),
                    pending_server_request_count: 0,
                    answered_but_unresolved_server_request_count: 0,
                    server_request_backlog_worker_counts: Vec::new(),
                    server_request_backlog_method_counts: Vec::new(),
                    result: Ok(()),
                });
            }
            Err(err) if err.kind() == ErrorKind::InvalidData => {
                return Ok(GatewayV2ConnectionRunResult {
                    outcome: "invalid_client_payload",
                    detail: Some(err.to_string()),
                    pending_client_request_count: 0,
                    pending_client_request_worker_counts: Vec::new(),
                    pending_client_request_method_counts: Vec::new(),
                    pending_server_request_count: 0,
                    answered_but_unresolved_server_request_count: 0,
                    server_request_backlog_worker_counts: Vec::new(),
                    server_request_backlog_method_counts: Vec::new(),
                    result: Ok(()),
                });
            }
            Err(err) => return Err(err),
        };
        let initialize_request_id = initialize_request.id.clone();
        let initialize_params = match request_params::<InitializeParams>(&initialize_request) {
            Ok(params) => params,
            Err(err) => {
                let detail = err.to_string();
                send_jsonrpc_error(
                    &mut socket,
                    initialize_request_id.clone(),
                    JSONRPCErrorError {
                        code: INVALID_REQUEST_CODE,
                        message: detail.clone(),
                        data: None,
                    },
                    timeouts.client_send,
                )
                .await
                .inspect_err(|err| {
                    let outcome = classify_v2_connection_error(err);
                    observe_client_response_send_failure(
                        &observability,
                        &context,
                        &initialize_request_id,
                        "initialize",
                        outcome,
                        err,
                    );
                })?;
                observe_v2_request(
                    &observability,
                    &context,
                    "initialize",
                    "invalid_request",
                    initialize_started_at.elapsed(),
                );
                return Ok(GatewayV2ConnectionRunResult {
                    outcome: "initialize_invalid_request",
                    detail: Some(detail),
                    pending_client_request_count: 0,
                    pending_client_request_worker_counts: Vec::new(),
                    pending_client_request_method_counts: Vec::new(),
                    pending_server_request_count: 0,
                    answered_but_unresolved_server_request_count: 0,
                    server_request_backlog_worker_counts: Vec::new(),
                    server_request_backlog_method_counts: Vec::new(),
                    result: Ok(()),
                });
            }
        };
        let mut downstream = match GatewayV2DownstreamRouter::connect_with_timeouts(
            &session_factory,
            &initialize_params,
            &context,
            &timeouts,
        )
        .await
        {
            Ok(downstream) => downstream,
            Err(err) => {
                let detail = err.to_string();
                let downstream_protocol_violation_reason =
                    downstream_protocol_violation_reason(&detail);
                let request_outcome = if downstream_protocol_violation_reason.is_some() {
                    "downstream_protocol_violation"
                } else {
                    "downstream_connect_error"
                };
                if let Some(reason) = downstream_protocol_violation_reason {
                    log_downstream_connect_protocol_violation(&context, reason, &detail);
                    observability.record_v2_protocol_violation("downstream", reason);
                }
                observe_v2_request(
                    &observability,
                    &context,
                    "initialize",
                    request_outcome,
                    initialize_started_at.elapsed(),
                );
                send_jsonrpc_error(
                    &mut socket,
                    initialize_request_id.clone(),
                    JSONRPCErrorError {
                        code: INTERNAL_ERROR_CODE,
                        message: format!("gateway failed to connect downstream app-server: {err}"),
                        data: None,
                    },
                    timeouts.client_send,
                )
                .await
                .inspect_err(|err| {
                    let outcome = classify_v2_connection_error(err);
                    observe_client_response_send_failure(
                        &observability,
                        &context,
                        &initialize_request_id,
                        "initialize",
                        outcome,
                        err,
                    );
                })?;
                return Ok(GatewayV2ConnectionRunResult {
                    outcome: request_outcome,
                    detail: Some(detail),
                    pending_client_request_count: 0,
                    pending_client_request_worker_counts: Vec::new(),
                    pending_client_request_method_counts: Vec::new(),
                    pending_server_request_count: 0,
                    answered_but_unresolved_server_request_count: 0,
                    server_request_backlog_worker_counts: Vec::new(),
                    server_request_backlog_method_counts: Vec::new(),
                    result: Ok(()),
                });
            }
        };
        send_jsonrpc(
            &mut socket,
            JSONRPCMessage::Response(JSONRPCResponse {
                id: initialize_request_id.clone(),
                result: serde_json::to_value(session_factory.initialize_response())
                    .map_err(io::Error::other)?,
            }),
            timeouts.client_send,
        )
        .await
        .inspect_err(|err| {
            let outcome = classify_v2_connection_error(err);
            observe_client_response_send_failure(
                &observability,
                &context,
                &initialize_request_id,
                "initialize",
                outcome,
                err,
            );
        })?;
        observe_v2_request(
            &observability,
            &context,
            "initialize",
            "ok",
            initialize_started_at.elapsed(),
        );

        let mut event_state = GatewayV2EventState {
            pending_server_requests: HashMap::new(),
            resolved_server_requests: HashMap::new(),
            skills_changed_pending_refresh: false,
            forwarded_connection_notifications: HashMap::new(),
        };
        let mut reject_pending_server_requests_on_exit = false;
        let mut connection_detail = None;
        let (pending_client_response_tx, mut pending_client_response_rx) =
            mpsc::channel::<PendingClientResponse>(timeouts.max_pending_client_requests.max(1));
        let mut pending_client_responses = PendingClientResponses {
            tx: pending_client_response_tx,
            tasks: Vec::new(),
            count: 0,
            active: HashMap::new(),
        };
        let connection = GatewayV2ConnectionContext {
            admission: &admission,
            observability: &observability,
            scope_registry: &scope_registry,
            request_context: &context,
            client_send_timeout: timeouts.client_send,
            max_pending_server_requests: timeouts.max_pending_server_requests,
            max_pending_client_requests: timeouts.max_pending_client_requests,
            opt_out_notification_methods: initialize_params
                .capabilities
                .as_ref()
                .and_then(|capabilities| capabilities.opt_out_notification_methods.clone())
                .unwrap_or_default()
                .into_iter()
                .collect(),
        };
        let mut reconnect_tick = tokio::time::interval_at(
            tokio::time::Instant::now() + timeouts.reconnect_retry_backoff,
            timeouts.reconnect_retry_backoff,
        );
        let (mut loop_result, mut connection_outcome): (io::Result<()>, &'static str) = loop {
            tokio::select! {
                frame = socket.recv() => {
                    let Some(frame) = frame else {
                        break (Ok(()), "client_disconnected");
                    };
                    match frame {
                        Ok(WebSocketMessage::Text(text)) => {
                            let message = match parse_client_jsonrpc_text(&text) {
                                Ok(message) => message,
                                Err(err) => {
                                    connection_detail = Some(err.to_string());
                                    connection.observability.record_v2_protocol_violation(
                                        "post_initialize",
                                        protocol_violation_reason_from_invalid_payload(&err),
                                    );
                                    send_observed_invalid_payload_close(
                                        &mut socket,
                                        connection.observability,
                                        connection.request_context,
                                        &err,
                                        timeouts.client_send,
                                    )
                                    .await?;
                                    reject_pending_server_requests_on_exit = true;
                                    break (Ok(()), "invalid_client_payload");
                                }
                            };
                            if let Err(err) = handle_client_message(
                                &mut socket,
                                &mut downstream,
                                &connection,
                                &mut event_state,
                                &mut pending_client_responses,
                                message,
                            )
                            .await {
                                let outcome = classify_v2_connection_error(&err);
                                break (Err(err), outcome);
                            }
                            update_active_v2_connection_pending_counts(
                                &observability,
                                connection_id,
                                &event_state,
                                &pending_client_responses.active,
                            );
                        }
                        Ok(WebSocketMessage::Binary(bytes)) => {
                            let message = match parse_client_jsonrpc_binary(&bytes) {
                                Ok(message) => message,
                                Err(err) => {
                                    connection_detail = Some(err.to_string());
                                    connection.observability.record_v2_protocol_violation(
                                        "post_initialize",
                                        protocol_violation_reason_from_invalid_payload(&err),
                                    );
                                    send_observed_invalid_payload_close(
                                        &mut socket,
                                        connection.observability,
                                        connection.request_context,
                                        &err,
                                        timeouts.client_send,
                                    )
                                    .await?;
                                    reject_pending_server_requests_on_exit = true;
                                    break (Ok(()), "invalid_client_payload");
                                }
                            };
                            if let Err(err) = handle_client_message(
                                &mut socket,
                                &mut downstream,
                                &connection,
                                &mut event_state,
                                &mut pending_client_responses,
                                message,
                            )
                            .await {
                                let outcome = classify_v2_connection_error(&err);
                                break (Err(err), outcome);
                            }
                            update_active_v2_connection_pending_counts(
                                &observability,
                                connection_id,
                                &event_state,
                                &pending_client_responses.active,
                            );
                        }
                        Ok(WebSocketMessage::Close(_)) => {
                            reject_pending_server_requests_on_exit = true;
                            break (Ok(()), "client_closed");
                        }
                        Ok(WebSocketMessage::Ping(payload)) => {
                            send_websocket_message(
                                &mut socket,
                                WebSocketMessage::Pong(payload),
                                timeouts.client_send,
                            )
                            .await?;
                        }
                        Ok(WebSocketMessage::Pong(_)) => {}
                        Err(err) => {
                            let err =
                                io::Error::other(format!("gateway websocket receive failed: {err}"));
                            let outcome = classify_v2_connection_error(&err);
                            break (Err(err), outcome);
                        }
                    }
                }
                event = downstream.next_event() => {
                    let Some(event) = event else {
                        send_observed_close_frame(
                            &mut socket,
                            &observability,
                            &context,
                            close_code::ERROR,
                            DOWNSTREAM_SESSION_ENDED_CLOSE_REASON,
                            timeouts.client_send,
                        )
                        .await?;
                        break (Ok(()), "downstream_session_ended");
                    };
                    let should_close = handle_app_server_event(
                        &mut socket,
                        &mut downstream,
                        &session_factory,
                        &connection,
                        &mut event_state,
                        &pending_client_responses.active,
                        event,
                    )
                    .await;
                    let should_close = match should_close {
                        Ok(should_close) => should_close,
                        Err(err) => {
                            let outcome = classify_v2_connection_error(&err);
                            break (Err(err), outcome);
                        }
                    };
                    if let Some(close) = should_close {
                        reject_pending_server_requests_on_exit = close.reject_pending_server_requests;
                        update_active_v2_connection_pending_counts(
                            &observability,
                            connection_id,
                            &event_state,
                            &pending_client_responses.active,
                        );
                        break (Ok(()), close.outcome);
                    }
                    update_active_v2_connection_pending_counts(
                        &observability,
                        connection_id,
                        &event_state,
                        &pending_client_responses.active,
                    );
                }
                _ = reconnect_tick.tick() => {
                    if downstream.reconnect_state.is_some() {
                        downstream
                            .reconnect_missing_workers(connection.observability)
                            .await;
                    }
                }
                pending_response = pending_client_response_rx.recv() => {
                    let Some(pending_response) = pending_response else {
                        continue;
                    };
                    let pending_response_request_id = pending_response.request_id.clone();
                    pending_client_responses.settle_response(&pending_response_request_id);
                    update_active_v2_connection_pending_counts(
                        &observability,
                        connection_id,
                        &event_state,
                        &pending_client_responses.active,
                    );
                    match pending_response.result {
                        Ok(Ok(result)) => {
                            if let Err(err) = send_jsonrpc(
                                &mut socket,
                                JSONRPCMessage::Response(JSONRPCResponse {
                                    id: pending_response.request_id.clone(),
                                    result,
                                }),
                                timeouts.client_send,
                            )
                            .await
                            {
                                let outcome = classify_v2_connection_error(&err);
                                observe_client_response_send_failure(
                                    &observability,
                                    &pending_response.request_context,
                                    &pending_response.request_id,
                                    &pending_response.method,
                                    outcome,
                                    &err,
                                );
                                observe_v2_request(
                                    &observability,
                                    &pending_response.request_context,
                                    &pending_response.method,
                                    outcome,
                                    pending_response.started_at.elapsed(),
                                );
                                break (Err(err), outcome);
                            }
                            observe_v2_request(
                                &observability,
                                &pending_response.request_context,
                                &pending_response.method,
                                "ok",
                                pending_response.started_at.elapsed(),
                            );
                        }
                        Ok(Err(error)) => {
                            let outcome = jsonrpc_error_outcome_code(error.code);
                            if let Err(err) = send_jsonrpc_error(
                                &mut socket,
                                pending_response.request_id.clone(),
                                error,
                                timeouts.client_send,
                            )
                            .await
                            {
                                let outcome = classify_v2_connection_error(&err);
                                observe_client_response_send_failure(
                                    &observability,
                                    &pending_response.request_context,
                                    &pending_response.request_id,
                                    &pending_response.method,
                                    outcome,
                                    &err,
                                );
                                observe_v2_request(
                                    &observability,
                                    &pending_response.request_context,
                                    &pending_response.method,
                                    outcome,
                                    pending_response.started_at.elapsed(),
                                );
                                break (Err(err), outcome);
                            }
                            observe_v2_request(
                                &observability,
                                &pending_response.request_context,
                                &pending_response.method,
                                outcome,
                                pending_response.started_at.elapsed(),
                            );
                        }
                        Err(err) => {
                            if let Err(send_err) = send_jsonrpc_error(
                                &mut socket,
                                pending_response.request_id.clone(),
                                JSONRPCErrorError {
                                    code: INTERNAL_ERROR_CODE,
                                    message: format!("gateway upstream request failed: {err}"),
                                    data: None,
                                },
                                timeouts.client_send,
                            )
                            .await
                            {
                                let outcome = classify_v2_connection_error(&send_err);
                                observe_client_response_send_failure(
                                    &observability,
                                    &pending_response.request_context,
                                    &pending_response.request_id,
                                    &pending_response.method,
                                    outcome,
                                    &send_err,
                                );
                                observe_v2_request(
                                    &observability,
                                    &pending_response.request_context,
                                    &pending_response.method,
                                    outcome,
                                    pending_response.started_at.elapsed(),
                                );
                                break (Err(send_err), outcome);
                            }
                            observe_v2_request(
                                &observability,
                                &pending_response.request_context,
                                &pending_response.method,
                                "internal_error",
                                pending_response.started_at.elapsed(),
                            );
                        }
                    }
                }
            }
        };

        pending_client_responses.settle_completed_responses(&mut pending_client_response_rx);
        if let Err(err) = &loop_result
            && err.kind() == ErrorKind::TimedOut
        {
            connection.observability.record_v2_client_send_timeout();
            log_client_send_timeout(
                connection.request_context,
                err.to_string().as_str(),
                &pending_client_responses.active,
                &event_state.pending_server_requests,
                &event_state.resolved_server_requests,
            );
        }

        let pending_client_request_count = pending_client_responses.count;
        let pending_client_request_worker_counts =
            pending_client_request_worker_counts(&pending_client_responses.active);
        let pending_client_request_method_counts =
            pending_client_request_method_counts(&pending_client_responses.active);
        if !pending_client_responses.active.is_empty() {
            log_aborted_pending_client_requests(
                connection.request_context,
                connection_outcome,
                connection_detail.as_deref(),
                &pending_client_responses.active,
            );
            observe_aborted_pending_client_requests(
                &observability,
                connection_outcome,
                &pending_client_responses.active,
            );
        }
        for task in pending_client_responses.tasks {
            task.abort();
        }

        let pending_server_request_count = event_state.pending_server_requests.len();
        let answered_but_unresolved_server_request_count =
            answered_but_unresolved_server_request_count(&event_state.resolved_server_requests);
        let server_request_backlog_worker_counts = server_request_backlog_worker_counts(
            &event_state.pending_server_requests,
            &event_state.resolved_server_requests,
        );
        let server_request_backlog_method_counts = server_request_backlog_method_counts(
            &event_state.pending_server_requests,
            &event_state.resolved_server_requests,
        );

        if (reject_pending_server_requests_on_exit
            || loop_result
                .as_ref()
                .err()
                .is_some_and(should_reject_pending_server_requests_after_connection_error))
            && let Err(err) = reject_pending_server_requests(
                &downstream,
                connection.observability,
                connection.request_context,
                connection_outcome,
                connection_detail.as_deref(),
                &mut event_state.pending_server_requests,
                &event_state.resolved_server_requests,
            )
            .await
            {
                connection_outcome = classify_v2_connection_error(&err);
                connection_detail = Some(err.to_string());
                loop_result = Err(err);
            }

        let shutdown_result = downstream.shutdown().await;
        let result = match loop_result {
            Ok(()) => {
                if let Err(err) = shutdown_result {
                    connection_outcome = classify_v2_connection_error(&err);
                    connection_detail = Some(err.to_string());
                    Err(err)
                } else {
                    Ok(())
                }
            }
            Err(err) => {
                connection_detail = Some(err.to_string());
                if let Err(shutdown_err) = shutdown_result {
                    observability.record_v2_downstream_shutdown_failure(connection_outcome);
                    let pending_counts = GatewayV2ConnectionPendingCounts {
                        pending_client_request_count,
                        pending_client_request_worker_counts: pending_client_request_worker_counts
                            .clone(),
                        pending_client_request_method_counts: pending_client_request_method_counts
                            .clone(),
                        pending_server_request_count,
                        answered_but_unresolved_server_request_count,
                        server_request_backlog_worker_counts: server_request_backlog_worker_counts
                            .clone(),
                        server_request_backlog_method_counts: server_request_backlog_method_counts
                            .clone(),
                    };
                    log_downstream_shutdown_failure(
                        connection.request_context,
                        connection_outcome,
                        connection_detail.as_deref(),
                        &pending_client_responses.active,
                        &pending_counts,
                        &shutdown_err,
                    );
                }
                Err(err)
            }
        };
        Ok(GatewayV2ConnectionRunResult {
            outcome: connection_outcome,
            detail: connection_detail,
            pending_client_request_count,
            pending_client_request_worker_counts,
            pending_client_request_method_counts,
            pending_server_request_count,
            answered_but_unresolved_server_request_count,
            server_request_backlog_worker_counts,
            server_request_backlog_method_counts,
            result,
        })
    }
    .await
    {
        Ok(run_result) => run_result,
        Err(err) => GatewayV2ConnectionRunResult {
            outcome: classify_v2_connection_error(&err),
            detail: Some(err.to_string()),
            pending_client_request_count: 0,
            pending_client_request_worker_counts: Vec::new(),
            pending_client_request_method_counts: Vec::new(),
            pending_server_request_count: 0,
            answered_but_unresolved_server_request_count: 0,
            server_request_backlog_worker_counts: Vec::new(),
            server_request_backlog_method_counts: Vec::new(),
            result: Err(err),
        },
    };
    observe_v2_connection(
        &observability,
        connection_id,
        &context,
        run_result.outcome,
        run_result.detail.as_deref(),
        GatewayV2ConnectionPendingCounts {
            pending_client_request_count: run_result.pending_client_request_count,
            pending_client_request_worker_counts: run_result.pending_client_request_worker_counts,
            pending_client_request_method_counts: run_result.pending_client_request_method_counts,
            pending_server_request_count: run_result.pending_server_request_count,
            answered_but_unresolved_server_request_count: run_result
                .answered_but_unresolved_server_request_count,
            server_request_backlog_worker_counts: run_result.server_request_backlog_worker_counts,
            server_request_backlog_method_counts: run_result.server_request_backlog_method_counts,
        },
        connection_started_at.elapsed(),
    );
    run_result.result
}

async fn recv_initialize_request(
    socket: &mut WebSocket,
    timeouts: GatewayV2Timeouts,
    observability: &GatewayObservability,
    context: &GatewayRequestContext,
) -> io::Result<JSONRPCRequest> {
    tokio::time::timeout(timeouts.initialize, async {
        loop {
            let Some(frame) = socket.recv().await else {
                return Err(io::Error::new(
                    ErrorKind::UnexpectedEof,
                    "gateway websocket connection closed before initialize",
                ));
            };
            match frame {
                Ok(WebSocketMessage::Text(text)) => {
                    let message = match parse_client_jsonrpc_text(&text) {
                        Ok(message) => message,
                        Err(err) => {
                            observability.record_v2_protocol_violation(
                                "pre_initialize",
                                protocol_violation_reason_from_invalid_payload(&err),
                            );
                            send_observed_invalid_payload_close(
                                socket,
                                observability,
                                context,
                                &err,
                                timeouts.client_send,
                            )
                            .await?;
                            return Err(err);
                        }
                    };
                    if let Some(request) = handle_pre_initialize_message(
                        socket,
                        message,
                        timeouts.client_send,
                        observability,
                        context,
                    )
                    .await?
                    {
                        return Ok(request);
                    }
                }
                Ok(WebSocketMessage::Binary(bytes)) => {
                    let message = match parse_client_jsonrpc_binary(&bytes) {
                        Ok(message) => message,
                        Err(err) => {
                            observability.record_v2_protocol_violation(
                                "pre_initialize",
                                protocol_violation_reason_from_invalid_payload(&err),
                            );
                            send_observed_invalid_payload_close(
                                socket,
                                observability,
                                context,
                                &err,
                                timeouts.client_send,
                            )
                            .await?;
                            return Err(err);
                        }
                    };
                    if let Some(request) = handle_pre_initialize_message(
                        socket,
                        message,
                        timeouts.client_send,
                        observability,
                        context,
                    )
                    .await?
                    {
                        return Ok(request);
                    }
                }
                Ok(WebSocketMessage::Ping(payload)) => {
                    send_websocket_message(
                        socket,
                        WebSocketMessage::Pong(payload),
                        timeouts.client_send,
                    )
                    .await?;
                }
                Ok(WebSocketMessage::Pong(_)) => {}
                Ok(WebSocketMessage::Close(_)) => {
                    return Err(io::Error::new(
                        ErrorKind::UnexpectedEof,
                        "gateway websocket connection closed before initialize",
                    ));
                }
                Err(err) => {
                    return Err(io::Error::other(format!(
                        "gateway websocket receive failed during initialize: {err}"
                    )));
                }
            }
        }
    })
    .await
    .map_err(|_| io::Error::new(ErrorKind::TimedOut, INITIALIZE_TIMEOUT_CLOSE_REASON))?
}

async fn handle_pre_initialize_message(
    socket: &mut WebSocket,
    message: JSONRPCMessage,
    client_send_timeout: Duration,
    observability: &GatewayObservability,
    context: &GatewayRequestContext,
) -> io::Result<Option<JSONRPCRequest>> {
    match message {
        JSONRPCMessage::Request(request) if request.method == "initialize" => Ok(Some(request)),
        JSONRPCMessage::Request(request) => {
            let started_at = Instant::now();
            let method = request.method.clone();
            observability.record_v2_protocol_violation("pre_initialize", "initialize_order");
            observe_v2_request(
                observability,
                context,
                &method,
                "invalid_request",
                started_at.elapsed(),
            );
            send_jsonrpc_error(
                socket,
                request.id.clone(),
                JSONRPCErrorError {
                    code: INVALID_REQUEST_CODE,
                    message: "initialize must be the first request".to_string(),
                    data: None,
                },
                client_send_timeout,
            )
            .await
            .inspect_err(|err| {
                let outcome = classify_v2_connection_error(err);
                observe_client_response_send_failure(
                    observability,
                    context,
                    &request.id,
                    &method,
                    outcome,
                    err,
                );
            })?;
            Ok(None)
        }
        JSONRPCMessage::Notification(_)
        | JSONRPCMessage::Response(_)
        | JSONRPCMessage::Error(_) => Ok(None),
    }
}

async fn handle_client_message(
    socket: &mut WebSocket,
    downstream: &mut GatewayV2DownstreamRouter,
    connection: &GatewayV2ConnectionContext<'_>,
    event_state: &mut GatewayV2EventState,
    pending_client_responses: &mut PendingClientResponses,
    message: JSONRPCMessage,
) -> io::Result<()> {
    match message {
        JSONRPCMessage::Request(request) => {
            let started_at = Instant::now();
            let method = request.method.clone();
            if request.method == "initialize" {
                connection
                    .observability
                    .record_v2_protocol_violation("post_initialize", "repeated_initialize");
                send_client_jsonrpc_error(
                    socket,
                    connection,
                    &request.id,
                    &method,
                    JSONRPCErrorError {
                        code: INVALID_REQUEST_CODE,
                        message: "connection is already initialized".to_string(),
                        data: None,
                    },
                )
                .await?;
                observe_v2_request(
                    connection.observability,
                    connection.request_context,
                    &method,
                    "invalid_request",
                    started_at.elapsed(),
                );
                return Ok(());
            }

            if let Err(err) = connection
                .admission
                .check_request(connection.request_context, request.method.as_str())
            {
                let outcome = gateway_error_outcome(&err);
                send_client_jsonrpc_error(
                    socket,
                    connection,
                    &request.id,
                    &method,
                    gateway_error_to_jsonrpc_error(err),
                )
                .await?;
                observe_v2_request(
                    connection.observability,
                    connection.request_context,
                    &method,
                    outcome,
                    started_at.elapsed(),
                );
                return Ok(());
            }

            if let Err(err) = enforce_request_scope(
                connection.scope_registry,
                connection.request_context,
                &request,
            ) {
                let outcome = gateway_error_outcome(&err);
                send_client_jsonrpc_error(
                    socket,
                    connection,
                    &request.id,
                    &method,
                    gateway_error_to_jsonrpc_error(err),
                )
                .await?;
                observe_v2_request(
                    connection.observability,
                    connection.request_context,
                    &method,
                    outcome,
                    started_at.elapsed(),
                );
                return Ok(());
            }

            let request_id = request.id.clone();
            let method = request.method.clone();
            if pending_client_responses.active.contains_key(&request_id) {
                log_duplicate_pending_client_request(
                    connection.request_context,
                    &request_id,
                    &method,
                    &pending_client_responses.active,
                );
                connection
                    .observability
                    .record_v2_protocol_violation("post_initialize", "duplicate_request_id");
                observe_v2_request(
                    connection.observability,
                    connection.request_context,
                    &method,
                    "protocol_violation",
                    started_at.elapsed(),
                );
                send_observed_close_frame(
                    socket,
                    connection.observability,
                    connection.request_context,
                    close_code::PROTOCOL,
                    DUPLICATE_PENDING_CLIENT_REQUEST_CLOSE_REASON,
                    connection.client_send_timeout,
                )
                .await?;
                return Err(io::Error::new(
                    ErrorKind::InvalidData,
                    DUPLICATE_PENDING_CLIENT_REQUEST_CLOSE_REASON,
                ));
            }
            if method == "command/exec" {
                if let Some(error) = pending_client_request_limit_error(
                    pending_client_responses.count,
                    connection.max_pending_client_requests,
                ) {
                    log_rejected_saturated_client_request(
                        connection.request_context,
                        &request_id,
                        &method,
                        pending_client_responses.count,
                        connection.max_pending_client_requests,
                    );
                    connection
                        .observability
                        .record_v2_client_request_rejection(&method, "pending_limit");
                    send_client_jsonrpc_error(socket, connection, &request_id, &method, error)
                        .await?;
                    observe_v2_request(
                        connection.observability,
                        connection.request_context,
                        &method,
                        "rate_limited",
                        started_at.elapsed(),
                    );
                    return Ok(());
                }
                if downstream.reconnect_state.is_some() {
                    downstream
                        .reconnect_missing_workers(connection.observability)
                        .await;
                }
                let worker = match worker_for_request(
                    downstream,
                    connection.scope_registry,
                    connection.request_context,
                    &request,
                ) {
                    Ok(worker) => worker.clone(),
                    Err(err) => {
                        log_fail_closed_multi_worker_request(
                            downstream,
                            connection,
                            method.as_str(),
                            &err,
                        );
                        observe_v2_request(
                            connection.observability,
                            connection.request_context,
                            &method,
                            "internal_error",
                            started_at.elapsed(),
                        );
                        return Err(err);
                    }
                };
                let client_request = jsonrpc_request_to_client_request(request)?;
                let request_context = connection.request_context.clone();
                let pending_client_response_tx = pending_client_responses.tx.clone();
                pending_client_responses.count += 1;
                pending_client_responses.active.insert(
                    request_id.clone(),
                    PendingClientRequestRoute {
                        method: method.clone(),
                        request_context: request_context.clone(),
                        worker_id: worker.worker_id,
                        worker_websocket_url: worker
                            .worker_websocket_url
                            .clone()
                            .unwrap_or_else(|| "<embedded>".to_string()),
                        started_at,
                    },
                );
                pending_client_responses
                    .tasks
                    .push(tokio::spawn(async move {
                        let result = worker.request_handle.request(client_request).await;
                        let _ = pending_client_response_tx
                            .send(PendingClientResponse {
                                request_id,
                                method,
                                request_context,
                                started_at,
                                result,
                            })
                            .await;
                    }));
                return Ok(());
            }
            match handle_client_request(downstream, connection, request).await {
                Ok(Ok(result)) => {
                    send_client_jsonrpc(
                        socket,
                        connection,
                        &request_id,
                        &method,
                        JSONRPCMessage::Response(JSONRPCResponse {
                            id: request_id.clone(),
                            result,
                        }),
                    )
                    .await?;
                    if downstream.multi_worker_topology() && method == "skills/list" {
                        event_state.skills_changed_pending_refresh = false;
                    }
                    observe_v2_request(
                        connection.observability,
                        connection.request_context,
                        &method,
                        "ok",
                        started_at.elapsed(),
                    );
                }
                Ok(Err(error)) => {
                    let outcome = jsonrpc_error_outcome_code(error.code);
                    send_client_jsonrpc_error(socket, connection, &request_id, &method, error)
                        .await?;
                    observe_v2_request(
                        connection.observability,
                        connection.request_context,
                        &method,
                        outcome,
                        started_at.elapsed(),
                    );
                }
                Err(err) => {
                    send_client_jsonrpc_error(
                        socket,
                        connection,
                        &request_id,
                        &method,
                        JSONRPCErrorError {
                            code: INTERNAL_ERROR_CODE,
                            message: format!("gateway upstream request failed: {err}"),
                            data: None,
                        },
                    )
                    .await?;
                    observe_v2_request(
                        connection.observability,
                        connection.request_context,
                        &method,
                        "internal_error",
                        started_at.elapsed(),
                    );
                }
            }
        }
        JSONRPCMessage::Notification(notification) => {
            let is_initialized = notification.method == "initialized";
            if is_initialized {
                downstream.mark_initialized();
            }
            if is_initialized && downstream.multi_worker_topology() {
                fanout_connection_notification(downstream, ClientNotification::Initialized).await?;
                return Ok(());
            }
            let worker =
                worker_for_notification(downstream, connection.scope_registry, &notification)?;
            let client_notification = jsonrpc_notification_to_client_notification(notification)?;
            worker.request_handle.notify(client_notification).await?;
        }
        JSONRPCMessage::Response(response) => {
            let gateway_request_id = response.id.clone();
            let Some(route) = event_state.pending_server_requests.remove(&response.id) else {
                log_unexpected_client_server_request_response(
                    connection.request_context,
                    "response",
                    &response.id,
                    &event_state.pending_server_requests,
                    &event_state.resolved_server_requests,
                );
                connection
                    .observability
                    .record_v2_server_request_lifecycle_event(
                        "unexpected_client_server_request_response",
                        "response",
                    );
                let err = io::Error::new(
                    ErrorKind::InvalidData,
                    format!(
                        "{UNEXPECTED_CLIENT_SERVER_REQUEST_RESPONSE_CLOSE_REASON}: {:?}",
                        response.id
                    ),
                );
                send_observed_invalid_payload_close(
                    socket,
                    connection.observability,
                    connection.request_context,
                    &err,
                    connection.client_send_timeout,
                )
                .await?;
                return Err(err);
            };
            event_state.resolved_server_requests.insert(
                DownstreamServerRequestKey {
                    worker_id: route.worker_id,
                    request_id: route.downstream_request_id.clone(),
                },
                ResolvedServerRequestRoute {
                    gateway_request_id: gateway_request_id.clone(),
                    worker_websocket_url: route.worker_websocket_url.clone(),
                    method: route.method.clone(),
                    thread_id: route.thread_id.clone(),
                },
            );
            deliver_client_server_request_answer(
                downstream,
                connection,
                gateway_request_id,
                route,
                ClientServerRequestAnswer::Response(response.result),
            )
            .await?;
        }
        JSONRPCMessage::Error(error) => {
            let gateway_request_id = error.id.clone();
            let Some(route) = event_state.pending_server_requests.remove(&error.id) else {
                log_unexpected_client_server_request_response(
                    connection.request_context,
                    "error",
                    &error.id,
                    &event_state.pending_server_requests,
                    &event_state.resolved_server_requests,
                );
                connection
                    .observability
                    .record_v2_server_request_lifecycle_event(
                        "unexpected_client_server_request_response",
                        "error",
                    );
                let err = io::Error::new(
                    ErrorKind::InvalidData,
                    format!(
                        "{UNEXPECTED_CLIENT_SERVER_REQUEST_RESPONSE_CLOSE_REASON}: {:?}",
                        error.id
                    ),
                );
                send_observed_invalid_payload_close(
                    socket,
                    connection.observability,
                    connection.request_context,
                    &err,
                    connection.client_send_timeout,
                )
                .await?;
                return Err(err);
            };
            event_state.resolved_server_requests.insert(
                DownstreamServerRequestKey {
                    worker_id: route.worker_id,
                    request_id: route.downstream_request_id.clone(),
                },
                ResolvedServerRequestRoute {
                    gateway_request_id: gateway_request_id.clone(),
                    worker_websocket_url: route.worker_websocket_url.clone(),
                    method: route.method.clone(),
                    thread_id: route.thread_id.clone(),
                },
            );
            deliver_client_server_request_answer(
                downstream,
                connection,
                gateway_request_id,
                route,
                ClientServerRequestAnswer::Error(error.error),
            )
            .await?;
        }
    }

    Ok(())
}

async fn deliver_client_server_request_answer(
    downstream: &GatewayV2DownstreamRouter,
    connection: &GatewayV2ConnectionContext<'_>,
    gateway_request_id: RequestId,
    route: PendingServerRequestRoute,
    answer: ClientServerRequestAnswer,
) -> io::Result<()> {
    let method_tag = answer.method_tag();
    let worker_id = route.worker_id;
    let worker_websocket_url = route.worker_websocket_url.clone();
    let downstream_request_id = route.downstream_request_id.clone();
    let thread_id = route.thread_id.clone();
    connection
        .observability
        .record_v2_server_request_lifecycle_event("client_server_request_answered", method_tag);
    let result = if downstream.multi_worker_topology()
        && let (Some(worker_id), Some(thread_id)) = (worker_id, thread_id.as_deref())
        && !downstream.worker_account_has_capacity(worker_id)
    {
        let message = format!(
            "thread {thread_id} is pinned to worker {worker_id} with exhausted account capacity for serverRequest/respond"
        );
        connection.observability.record_v2_account_capacity_event(
            worker_id,
            "active_thread_handoff_failure",
            Some(connection.request_context),
            Some(message.as_str()),
        );
        connection.observability.publish_operator_event(
            GatewayEvent::account_active_thread_handoff_failed(
                GatewayAccountActiveThreadHandoffFailed {
                    tenant_id: connection.request_context.tenant_id.as_str(),
                    project_id: connection.request_context.project_id.as_deref(),
                    method: "serverRequest/respond",
                    thread_id,
                    exhausted_worker_id: worker_id,
                    exhausted_account_id: downstream.worker_account_id(worker_id),
                    reason: message.as_str(),
                },
            ),
        );
        warn!(
            response_kind = method_tag,
            account_capacity_event = "active_thread_handoff_failure",
            tenant_id = connection.request_context.tenant_id.as_str(),
            project_id = connection.request_context.project_id.as_deref(),
            thread_id,
            exhausted_worker_id = worker_id,
            exhausted_account_id = downstream.worker_account_id(worker_id),
            "gateway v2 failed closed for an answered server request pinned to an exhausted account because no protocol-visible context handoff was requested"
        );
        Err(io::Error::other(FailClosedMultiWorkerRouteError {
            message,
        }))
    } else {
        match worker_for_server_request(downstream, worker_id) {
            Ok(worker) => match answer {
                ClientServerRequestAnswer::Response(result) => {
                    worker
                        .request_handle
                        .resolve_server_request(route.downstream_request_id, result)
                        .await
                }
                ClientServerRequestAnswer::Error(error) => {
                    worker
                        .request_handle
                        .reject_server_request(route.downstream_request_id, error)
                        .await
                }
            },
            Err(err) => Err(err),
        }
    };
    let event = if result.is_ok() {
        "client_server_request_delivered"
    } else {
        "client_server_request_delivery_failed"
    };
    connection
        .observability
        .record_v2_server_request_lifecycle_event(event, method_tag);
    if let Err(err) = &result {
        connection
            .observability
            .record_v2_server_request_answer_delivery_failure(method_tag);
        warn!(
            tenant_id = connection.request_context.tenant_id.as_str(),
            project_id = connection.request_context.project_id.as_deref(),
            response_kind = method_tag,
            worker_id = ?worker_id,
            worker_websocket_url,
            gateway_request_id = ?gateway_request_id,
            downstream_request_id = ?downstream_request_id,
            thread_id = thread_id.as_deref(),
            error = %err,
            "failed to deliver answered server request back to downstream worker"
        );
    }
    result
}

async fn reject_downstream_server_request_at_gateway_boundary(
    downstream: &GatewayV2DownstreamRouter,
    connection: &GatewayV2ConnectionContext<'_>,
    request: GatewayRejectedServerRequest<'_>,
    error: JSONRPCErrorError,
) -> io::Result<()> {
    let downstream_request_id_for_log = request.downstream_request_id.clone();
    let result = match worker_for_server_request(downstream, request.worker_id) {
        Ok(worker) => {
            worker
                .request_handle
                .reject_server_request(request.downstream_request_id, error)
                .await
        }
        Err(err) => Err(err),
    };
    let event = if result.is_ok() {
        "downstream_server_request_rejection_delivered"
    } else {
        "downstream_server_request_rejection_delivery_failed"
    };
    connection
        .observability
        .record_v2_server_request_lifecycle_event(event, request.method);
    if let Err(err) = &result {
        connection
            .observability
            .record_v2_server_request_rejection_delivery_failure(request.method);
        warn!(
            tenant_id = connection.request_context.tenant_id.as_str(),
            project_id = connection.request_context.project_id.as_deref(),
            worker_id = ?request.worker_id,
            worker_websocket_url = request.worker_websocket_url,
            gateway_request_id = ?request.gateway_request_id,
            downstream_request_id = ?downstream_request_id_for_log,
            method = request.method,
            error = %err,
            "failed to deliver gateway rejected server request back to downstream worker"
        );
    }
    result
}

async fn handle_app_server_event(
    socket: &mut WebSocket,
    downstream: &mut GatewayV2DownstreamRouter,
    session_factory: &GatewayV2SessionFactory,
    connection: &GatewayV2ConnectionContext<'_>,
    event_state: &mut GatewayV2EventState,
    _pending_client_requests: &HashMap<RequestId, PendingClientRequestRoute>,
    downstream_event: DownstreamWorkerEvent,
) -> io::Result<Option<GatewayV2ConnectionClose>> {
    let worker_id = downstream_event.worker_id;
    if worker_id.is_some() && !downstream.has_worker(worker_id) && downstream.worker_count() > 0 {
        return Ok(None);
    }
    let worker_websocket_url = downstream
        .websocket_url_for_worker_id(worker_id)
        .to_string();
    let Some(event) = downstream_event.event else {
        let mut cleanup = WorkerServerRequestCleanup::default();
        if (downstream.reconnect_state.is_some() || !downstream.single_worker())
            && downstream.remove_worker(worker_id)
        {
            cleanup = resolve_server_requests_for_worker(
                socket,
                connection,
                &mut event_state.pending_server_requests,
                &mut event_state.resolved_server_requests,
                worker_id,
                WorkerServerRequestCleanupReport {
                    worker_websocket_url: worker_websocket_url.as_str(),
                    remaining_worker_count: downstream.worker_count(),
                    disconnect_message: None,
                    message: "downstream worker session ended within shared gateway v2 session",
                },
            )
            .await?;
            if cleanup.has_stranded_connection_scoped_requests() {
                send_observed_close_frame(
                    socket,
                    connection.observability,
                    connection.request_context,
                    close_code::ERROR,
                    STRANDED_CONNECTION_SERVER_REQUEST_CLOSE_REASON,
                    connection.client_send_timeout,
                )
                .await?;
                return Ok(Some(GatewayV2ConnectionClose {
                    outcome: "stranded_connection_scoped_server_request",
                    reject_pending_server_requests: true,
                }));
            }
            if downstream.reconnect_state.is_some() {
                downstream
                    .reconnect_missing_workers_after_disconnect(connection.observability)
                    .await;
            }
            if downstream.reconnect_state.is_some() && downstream.worker_count() > 0 {
                return Ok(None);
            }
            if downstream.worker_count() > 0 {
                return Ok(None);
            }
        } else if worker_id.is_none() {
            cleanup = resolve_server_requests_for_worker(
                socket,
                connection,
                &mut event_state.pending_server_requests,
                &mut event_state.resolved_server_requests,
                worker_id,
                WorkerServerRequestCleanupReport {
                    worker_websocket_url: worker_websocket_url.as_str(),
                    remaining_worker_count: 0,
                    disconnect_message: None,
                    message: "downstream app-server session ended with unresolved gateway server requests",
                },
            )
            .await?;
        }
        if cleanup.has_stranded_connection_scoped_requests() {
            send_observed_close_frame(
                socket,
                connection.observability,
                connection.request_context,
                close_code::ERROR,
                STRANDED_CONNECTION_SERVER_REQUEST_CLOSE_REASON,
                connection.client_send_timeout,
            )
            .await?;
            return Ok(Some(GatewayV2ConnectionClose {
                outcome: "stranded_connection_scoped_server_request",
                reject_pending_server_requests: true,
            }));
        }
        send_observed_close_frame(
            socket,
            connection.observability,
            connection.request_context,
            close_code::ERROR,
            DOWNSTREAM_SESSION_ENDED_CLOSE_REASON,
            connection.client_send_timeout,
        )
        .await?;
        return Ok(Some(GatewayV2ConnectionClose {
            outcome: "downstream_session_ended",
            reject_pending_server_requests: false,
        }));
    };
    match event {
        AppServerEvent::Lagged { skipped } => {
            log_downstream_backpressure_close(
                connection.request_context,
                worker_id,
                worker_websocket_url.as_str(),
                skipped,
                &event_state.pending_server_requests,
                &event_state.resolved_server_requests,
            );
            connection
                .observability
                .record_v2_downstream_backpressure(worker_id);
            send_observed_close_frame(
                socket,
                connection.observability,
                connection.request_context,
                close_code::POLICY,
                &format_lagged_close_reason(skipped),
                connection.client_send_timeout,
            )
            .await?;
            return Ok(Some(GatewayV2ConnectionClose {
                outcome: "downstream_backpressure",
                reject_pending_server_requests: true,
            }));
        }
        AppServerEvent::ServerNotification(notification) => {
            sync_worker_account_capacity_from_notification(
                downstream,
                connection.request_context,
                connection.observability,
                worker_id,
                &notification,
            );
            let Some(notification) = server_notification_to_jsonrpc(
                notification,
                connection.request_context,
                connection.observability,
                worker_id,
                worker_websocket_url.as_str(),
                &mut event_state.resolved_server_requests,
            )?
            else {
                return Ok(None);
            };
            if connection
                .opt_out_notification_methods
                .contains(notification.method.as_str())
            {
                log_suppressed_opted_out_notification(
                    connection.request_context,
                    worker_id,
                    worker_websocket_url.as_str(),
                    &notification,
                );
                connection
                    .observability
                    .record_v2_suppressed_notification(&notification.method, "opted_out");
                return Ok(None);
            }
            if downstream.multi_worker_topology()
                && notification.method == "skills/changed"
                && event_state.skills_changed_pending_refresh
            {
                log_suppressed_skills_changed_notification(
                    connection.request_context,
                    worker_id,
                    worker_websocket_url.as_str(),
                    &notification,
                );
                connection
                    .observability
                    .record_v2_suppressed_notification(&notification.method, "pending_refresh");
                return Ok(None);
            }
            if downstream.multi_worker_topology()
                && should_deduplicate_connection_notification(&notification)
                && let Some(forwarded_notification) = forwarded_connection_notification_duplicate(
                    &event_state.forwarded_connection_notifications,
                    worker_id,
                    &notification,
                )
            {
                log_suppressed_duplicate_connection_notification(
                    connection.request_context,
                    worker_id,
                    worker_websocket_url.as_str(),
                    forwarded_notification.worker_id,
                    downstream.websocket_url_for_worker_id(forwarded_notification.worker_id),
                    &notification,
                );
                connection
                    .observability
                    .record_v2_suppressed_notification(&notification.method, "duplicate");
                return Ok(None);
            }
            if notification_visible_to(
                connection.scope_registry,
                connection.request_context,
                &notification,
            ) {
                if downstream.multi_worker_topology() && notification.method == "skills/changed" {
                    event_state.skills_changed_pending_refresh = true;
                }
                if downstream.multi_worker_topology()
                    && should_deduplicate_connection_notification(&notification)
                {
                    record_forwarded_connection_notification(
                        &mut event_state.forwarded_connection_notifications,
                        worker_id,
                        &notification,
                    );
                }
                let method = notification.method.clone();
                if let Err(err) = send_jsonrpc(
                    socket,
                    JSONRPCMessage::Notification(notification),
                    connection.client_send_timeout,
                )
                .await
                {
                    let outcome = classify_v2_connection_error(&err);
                    log_notification_send_failure(
                        connection.request_context,
                        worker_id,
                        worker_websocket_url.as_str(),
                        &method,
                        outcome,
                        &err,
                    );
                    connection
                        .observability
                        .record_v2_notification_send_failure(&method, outcome);
                    return Err(err);
                }
                connection
                    .observability
                    .record_v2_forwarded_notification(&method);
            } else {
                log_suppressed_hidden_thread_notification(
                    connection.request_context,
                    worker_id,
                    worker_websocket_url.as_str(),
                    &notification,
                );
                connection
                    .observability
                    .record_v2_suppressed_notification(&notification.method, "hidden_thread");
            }
        }
        AppServerEvent::ServerRequest(request) => {
            let gateway_request_id = if downstream.multi_worker_topology() {
                session_factory.next_server_request_id()
            } else {
                request.id().clone()
            };
            let (request, downstream_request_id) =
                server_request_to_jsonrpc(request, gateway_request_id)?;
            if event_state
                .pending_server_requests
                .contains_key(&request.id)
            {
                log_duplicate_downstream_server_request(
                    connection.request_context,
                    worker_id,
                    worker_websocket_url.as_str(),
                    &request.id,
                    &request.method,
                    &event_state.pending_server_requests,
                );
                connection
                    .observability
                    .record_v2_server_request_lifecycle_event(
                        "duplicate_pending_request",
                        &request.method,
                    );
                send_observed_close_frame(
                    socket,
                    connection.observability,
                    connection.request_context,
                    close_code::ERROR,
                    DUPLICATE_DOWNSTREAM_SERVER_REQUEST_CLOSE_REASON,
                    connection.client_send_timeout,
                )
                .await?;
                return Ok(Some(GatewayV2ConnectionClose {
                    outcome: "duplicate_downstream_server_request",
                    reject_pending_server_requests: true,
                }));
            }
            if server_request_visible_to(
                connection.scope_registry,
                connection.request_context,
                &request,
            ) {
                if let Some(error) = pending_server_request_limit_error(
                    event_state.pending_server_requests.len(),
                    connection.max_pending_server_requests,
                ) {
                    log_rejected_saturated_server_request(
                        connection.request_context,
                        worker_id,
                        worker_websocket_url.as_str(),
                        &request.id,
                        &request.method,
                        &event_state.pending_server_requests,
                        connection.max_pending_server_requests,
                    );
                    connection
                        .observability
                        .record_v2_server_request_rejection(&request.method, "pending_limit");
                    connection
                        .observability
                        .record_v2_server_request_lifecycle_event(
                            "downstream_server_request_rejected_pending_limit",
                            &request.method,
                        );
                    reject_downstream_server_request_at_gateway_boundary(
                        downstream,
                        connection,
                        GatewayRejectedServerRequest {
                            worker_id,
                            worker_websocket_url: worker_websocket_url.as_str(),
                            gateway_request_id: &request.id,
                            method: &request.method,
                            downstream_request_id,
                        },
                        error,
                    )
                    .await?;
                    return Ok(None);
                }
                event_state.pending_server_requests.insert(
                    request.id.clone(),
                    PendingServerRequestRoute {
                        worker_id,
                        worker_websocket_url: worker_websocket_url.clone(),
                        downstream_request_id,
                        method: request.method.clone(),
                        thread_id: request_thread_id(&request).map(str::to_string),
                    },
                );
                let method = request.method.clone();
                if let Err(err) = send_jsonrpc(
                    socket,
                    JSONRPCMessage::Request(request),
                    connection.client_send_timeout,
                )
                .await
                {
                    let outcome = classify_v2_connection_error(&err);
                    log_downstream_server_request_forward_failure(
                        connection.request_context,
                        worker_id,
                        worker_websocket_url.as_str(),
                        &method,
                        outcome,
                        &err,
                    );
                    connection
                        .observability
                        .record_v2_server_request_forward_send_failure(&method, outcome);
                    connection
                        .observability
                        .record_v2_server_request_lifecycle_event(
                            "downstream_server_request_forward_delivery_failed",
                            &method,
                        );
                    return Err(err);
                }
                connection
                    .observability
                    .record_v2_server_request_lifecycle_event(
                        "downstream_server_request_forwarded",
                        &method,
                    );
            } else {
                log_rejected_hidden_downstream_server_request(
                    connection.request_context,
                    worker_id,
                    worker_websocket_url.as_str(),
                    &request.id,
                    &request.method,
                    request_thread_id(&request),
                );
                connection
                    .observability
                    .record_v2_server_request_rejection(&request.method, "hidden_thread");
                connection
                    .observability
                    .record_v2_server_request_lifecycle_event(
                        "downstream_server_request_rejected_hidden_thread",
                        &request.method,
                    );
                let message = hidden_thread_error_message(&request).to_string();
                reject_downstream_server_request_at_gateway_boundary(
                    downstream,
                    connection,
                    GatewayRejectedServerRequest {
                        worker_id,
                        worker_websocket_url: worker_websocket_url.as_str(),
                        gateway_request_id: &request.id,
                        method: &request.method,
                        downstream_request_id,
                    },
                    JSONRPCErrorError {
                        code: INVALID_PARAMS_CODE,
                        message,
                        data: None,
                    },
                )
                .await?;
            }
        }
        AppServerEvent::Disconnected { message } => {
            let protocol_violation_reason = downstream_protocol_violation_reason(message.as_str());
            if let Some(reason) = protocol_violation_reason {
                log_downstream_protocol_violation(
                    connection.request_context,
                    worker_id,
                    worker_websocket_url.as_str(),
                    reason,
                    message.as_str(),
                    downstream.worker_count(),
                    event_state,
                );
                connection
                    .observability
                    .record_v2_worker_protocol_violation(worker_id, "downstream", reason);
                send_observed_close_frame(
                    socket,
                    connection.observability,
                    connection.request_context,
                    close_code::ERROR,
                    &format!("downstream app-server disconnected: {message}"),
                    connection.client_send_timeout,
                )
                .await?;
                return Ok(Some(GatewayV2ConnectionClose {
                    outcome: "downstream_protocol_violation",
                    reject_pending_server_requests: true,
                }));
            }
            let mut cleanup = WorkerServerRequestCleanup::default();
            if (downstream.reconnect_state.is_some() || !downstream.single_worker())
                && downstream.remove_worker(worker_id)
            {
                cleanup = resolve_server_requests_for_worker(
                    socket,
                    connection,
                    &mut event_state.pending_server_requests,
                    &mut event_state.resolved_server_requests,
                    worker_id,
                    WorkerServerRequestCleanupReport {
                        worker_websocket_url: worker_websocket_url.as_str(),
                        remaining_worker_count: downstream.worker_count(),
                        disconnect_message: Some(message.as_str()),
                        message: "downstream worker disconnected within shared gateway v2 session",
                    },
                )
                .await?;
                if cleanup.has_stranded_connection_scoped_requests() {
                    send_observed_close_frame(
                        socket,
                        connection.observability,
                        connection.request_context,
                        close_code::ERROR,
                        STRANDED_CONNECTION_SERVER_REQUEST_CLOSE_REASON,
                        connection.client_send_timeout,
                    )
                    .await?;
                    return Ok(Some(GatewayV2ConnectionClose {
                        outcome: "stranded_connection_scoped_server_request",
                        reject_pending_server_requests: true,
                    }));
                }
                if downstream.reconnect_state.is_some() {
                    downstream
                        .reconnect_missing_workers_after_disconnect(connection.observability)
                        .await;
                }
                if downstream.reconnect_state.is_some() && downstream.worker_count() > 0 {
                    return Ok(None);
                }
                if downstream.worker_count() > 0 {
                    return Ok(None);
                }
            } else if worker_id.is_none() {
                cleanup = resolve_server_requests_for_worker(
                    socket,
                    connection,
                    &mut event_state.pending_server_requests,
                    &mut event_state.resolved_server_requests,
                    worker_id,
                    WorkerServerRequestCleanupReport {
                        worker_websocket_url: worker_websocket_url.as_str(),
                        remaining_worker_count: 0,
                        disconnect_message: Some(message.as_str()),
                        message: "downstream app-server disconnected with unresolved gateway server requests",
                    },
                )
                .await?;
            }
            if cleanup.has_stranded_connection_scoped_requests() {
                send_observed_close_frame(
                    socket,
                    connection.observability,
                    connection.request_context,
                    close_code::ERROR,
                    STRANDED_CONNECTION_SERVER_REQUEST_CLOSE_REASON,
                    connection.client_send_timeout,
                )
                .await?;
                return Ok(Some(GatewayV2ConnectionClose {
                    outcome: "stranded_connection_scoped_server_request",
                    reject_pending_server_requests: true,
                }));
            }
            send_observed_close_frame(
                socket,
                connection.observability,
                connection.request_context,
                close_code::ERROR,
                &format!("downstream app-server disconnected: {message}"),
                connection.client_send_timeout,
            )
            .await?;
            return Ok(Some(GatewayV2ConnectionClose {
                outcome: if protocol_violation_reason.is_some() {
                    "downstream_protocol_violation"
                } else {
                    "downstream_session_ended"
                },
                reject_pending_server_requests: false,
            }));
        }
    }

    Ok(None)
}

async fn resolve_server_requests_for_worker(
    socket: &mut WebSocket,
    connection: &GatewayV2ConnectionContext<'_>,
    pending_server_requests: &mut HashMap<RequestId, PendingServerRequestRoute>,
    resolved_server_requests: &mut HashMap<DownstreamServerRequestKey, ResolvedServerRequestRoute>,
    worker_id: Option<usize>,
    report: WorkerServerRequestCleanupReport<'_>,
) -> io::Result<WorkerServerRequestCleanup> {
    let cleanup = collect_server_request_cleanup_for_worker(
        pending_server_requests,
        resolved_server_requests,
        worker_id,
    );

    record_worker_server_request_cleanup_metrics(connection.observability, &cleanup);
    if cleanup.has_cleaned_up_requests() {
        report_worker_server_request_cleanup(
            connection.observability,
            worker_id,
            &report,
            &cleanup,
        );
    }

    for resolved_notification in &cleanup.resolved_notifications {
        let method = resolved_notification.method.as_str();
        if let Err(err) = send_jsonrpc(
            socket,
            JSONRPCMessage::Notification(tagged_type_to_notification(
                ServerNotification::ServerRequestResolved(
                    resolved_notification.notification.clone(),
                ),
            )?),
            connection.client_send_timeout,
        )
        .await
        {
            record_worker_cleanup_resolution_send_failure(
                connection.observability,
                connection.request_context,
                worker_id,
                report.worker_websocket_url,
                resolved_notification,
                &err,
            );
            return Err(err);
        }
        connection
            .observability
            .record_v2_server_request_lifecycle_event(
                "worker_cleanup_resolution_delivered",
                method,
            );
    }

    Ok(cleanup)
}

fn report_worker_server_request_cleanup(
    observability: &GatewayObservability,
    worker_id: Option<usize>,
    report: &WorkerServerRequestCleanupReport<'_>,
    cleanup: &WorkerServerRequestCleanup,
) {
    log_worker_server_request_cleanup(
        worker_id,
        report.worker_websocket_url,
        report.remaining_worker_count,
        report.disconnect_message,
        cleanup,
        report.message,
    );
    publish_worker_server_request_cleanup_event(
        observability,
        worker_id,
        report.worker_websocket_url,
        report.remaining_worker_count,
        report.disconnect_message,
        cleanup,
    );
}

fn record_worker_cleanup_resolution_send_failure(
    observability: &GatewayObservability,
    request_context: &GatewayRequestContext,
    worker_id: Option<usize>,
    worker_websocket_url: &str,
    resolved_notification: &WorkerCleanupResolvedNotification,
    err: &io::Error,
) {
    let outcome = classify_v2_connection_error(err);
    let notification = &resolved_notification.notification;
    let method = resolved_notification.method.as_str();
    observability.record_v2_notification_send_failure("serverRequest/resolved", outcome);
    observability
        .record_v2_server_request_lifecycle_event("worker_cleanup_resolution_send_failed", method);
    warn!(
        tenant_id = %request_context.tenant_id,
        project_id = ?request_context.project_id,
        worker_id = ?worker_id,
        worker_websocket_url,
        thread_id = notification.thread_id.as_str(),
        gateway_request_id = ?notification.request_id,
        method,
        outcome,
        %err,
        "failed to deliver synthesized serverRequest/resolved during worker cleanup"
    );
}

